import{_ as i,C as r,o as n,c as l,j as a,a as u,E as o,al as d}from"./chunks/framework.Cru2ZAWp.js";const _=JSON.parse('{"title":"Mise à jour Firmware (DFU)","description":"","frontmatter":{},"headers":[],"relativePath":"fr/examples/dfu.md","filePath":"fr/examples/dfu.md"}'),c={name:"fr/examples/dfu.md"};function p(m,e,f,g,h,v){const t=r("DfuDemo"),s=r("BoksDashboard");return n(),l("div",null,[e[0]||(e[0]=a("h1",{id:"mise-a-jour-firmware-dfu",tabindex:"-1"},[u("Mise à jour Firmware (DFU) "),a("a",{class:"header-anchor",href:"#mise-a-jour-firmware-dfu","aria-label":'Permalink to "Mise à jour Firmware (DFU)"'},"​")],-1)),o(t),e[1]||(e[1]=d('<p>Cette démo interactive vous permet de mettre à jour le firmware de votre appareil Boks. Elle utilise la bibliothèque <code>@thib3113/web-bluetooth-dfu</code> pour flasher de manière sécurisée les paquets de mise à jour <code>.zip</code> de Nordic Semiconductor.</p><h2 id="comment-ca-marche" tabindex="-1">Comment ça marche <a class="header-anchor" href="#comment-ca-marche" aria-label="Permalink to &quot;Comment ça marche&quot;">​</a></h2><p>La mise à jour du firmware est un processus en deux étapes :</p><ol><li><p><strong>Préparation (Mode Normal)</strong> :</p><ul><li>Lorsque vous vous connectez à votre appareil Boks (ex : <code>Boks-1234</code>), l&#39;outil lit les versions actuelles du matériel, du logiciel et le niveau de la batterie.</li><li>Si la batterie est inférieure à 20 %, vous serez averti de la changer avant de continuer.</li><li>En appuyant sur &quot;Passer en mode DFU&quot;, l&#39;outil écrit <code>0x01</code> dans la caractéristique de contrôle DFU, ce qui provoque le redémarrage de l&#39;appareil dans un état de bootloader spécialisé.</li></ul></li><li><p><strong>Flashage (Mode DFU)</strong> :</p><ul><li>Une fois l&#39;appareil redémarré, vous serez déconnecté.</li><li>Rouvrez le panneau de connexion et connectez-vous à nouveau à l&#39;appareil (il s&#39;annoncera sous le nom de <code>DfuTarg</code> ou <code>Boks_DFU</code>).</li><li>Vous pouvez immédiatement sélectionner votre fichier <code>.zip</code> de firmware et démarrer le processus de flashage.</li><li>L&#39;appareil redémarrera en fonctionnement normal une fois le transfert vérifié et terminé.</li></ul></li></ol><h2 id="faq-cruciale-informations-de-securite" tabindex="-1">FAQ Cruciale &amp; Informations de Sécurité <a class="header-anchor" href="#faq-cruciale-informations-de-securite" aria-label="Permalink to &quot;FAQ Cruciale &amp; Informations de Sécurité&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Récupération suite à une interruption</p><p>Tous les appareils Boks ne récupèrent pas d&#39;une DFU interrompue de la même manière.</p><ul><li><strong>Boks V3 (nRF52811)</strong> : Si la mise à jour est interrompue (navigateur fermé, coupure de courant), l&#39;appareil sera <strong>temporairement indisponible</strong> ou <strong>bloqué en mode mise à jour</strong>. Il reste dans l&#39;état du bootloader, empêchant toute interaction normale. Il suffit de réussir un nouveau flash pour restaurer l&#39;appareil.</li><li><strong>Boks V4 (nRF52833)</strong> : Le bootloader sur les appareils plus récents gère les interruptions plus gracieusement. Un retrait de la batterie (retirer et réinsérer les piles) peut généralement restaurer l&#39;appareil à son état précédent.</li></ul></div><p><strong>Q: Puis-je flasher une version plus ancienne (downgrade) ?</strong> R: Généralement, non. Le bootloader contient une protection contre le downgrade (Erreur <code>0x0E</code>). Vous ne pouvez flasher que des versions égales ou supérieures à votre installation actuelle.</p><p><strong>Q: Que se passe-t-il si je flashe un firmware non signé par Boks ?</strong> R: Le bootloader DFU nécessite des paquets de firmware signés cryptographiquement. Flasher des zips non signés ou mal signés entraînera une Erreur d&#39;Authentification (<code>0x0C</code>).</p>',8)),o(s)])}const q=i(c,[["render",p]]);export{_ as __pageData,q as default};
